    int n = online.length;
    java.util.Map<Integer, java.util.List<int[]>> graph = new java.util.HashMap<>();
    for (int i = 0; i < edges.length; i++) {
        int u = (int) edges[i][0];
        int v = (int) edges[i][1];
        int cost = (int) edges[i][2];
        graph.putIfAbsent(u, new java.util.ArrayList<>());
        graph.get(u).add(new int[]{v, cost});
    }

    java.util.PriorityQueue<int[]> maxHeap = new java.util.PriorityQueue<>((a, b) -> {
        return Long.compare(b[0], a[0]);
    });
